const items = $input.all();
const body = items[0]?.json?.body || items[0]?.json || {};
const query = body.query || "";

let isValid = true;
let errorReason = "";

if (typeof query !== 'string') {
  isValid = false;
  errorReason = "Query must be a string.";
} else {
  const trimmed = query.trim();
  if (trimmed.length < 3 || trimmed.length > 100) {
    isValid = false;
    errorReason = "Query length must be between 3 and 100 characters.";
  } else {
    if (/<script|javascript:|select\s+.*\s+from/i.test(trimmed)) {
      isValid = false;
      errorReason = "Query contains restricted special characters or patterns.";
    }
  }
}

return [{
  json: {
    query: query,
    isValid: isValid,
    error: errorReason
  }
}];

const items = $input.all();
const fundData = $('Fetch Fund Data').first().json;
const webhookInput = $('Webhook').first().json.body || {};

let category = "General";
if (fundData.enriched) {
  const searchResult = $('Fetch Category Info').first().json.body?.data?.list || [];
  if (searchResult.length > 0) {
    category = searchResult[0].category || searchResult[0].sebi_category_name || "General";
  }
}

let isValid = true;
let errorReason = "";

// AUM checks — only enforce when enriched data is available
if (fundData.enriched) {
  const aum = parseFloat(fundData.aum);
  if (isNaN(aum) || aum <= 0) {
    isValid = false;
    errorReason = `Invalid Net Assets (AUM): AUM must be greater than 0 (got ${fundData.aum}).`;
  }
}

// Holdings checks — only enforce when enriched data is available
// Data layer outputs holdings with field name 'weight' (not 'weight_percent' or 'Portfolio_Weight')
const holdings = fundData.holdings || [];
if (isValid && fundData.enriched) {
  let totalWeight = 0;
  for (const h of holdings) {
    const weight = parseFloat(h.weight || h.weight_percent || h.Portfolio_Weight) || 0;
    totalWeight += weight;
  }
  if (totalWeight <= 0 || totalWeight > 100) {
    isValid = false;
    errorReason = `Holdings weight checks failed: Sum of weights must be > 0% and <= 100% (got ${totalWeight}%).`;
  }
}

// NAV History checks
const navHistory = fundData.nav_history || [];
if (isValid && navHistory.length < 20) {
  isValid = false;
  errorReason = `NAV history length check failed: Must contain at least 20 historical date records (got ${navHistory.length}).`;
}

// Required fields verification
if (isValid) {
  if (!fundData.name || !fundData.scheme_code) {
    isValid = false;
    errorReason = "Required schema fields 'name' or 'scheme_code' are missing from fund details.";
  }
}

const output = {
  query: webhookInput.query || "",
  scheme_id: fundData.scheme_code,
  scheme_name: fundData.name,
  isin: fundData.isin || fundData.scheme_isin || "",
  amc_name: fundData.amc_name || "",
  category: category,
  enriched: fundData.enriched,
  aum: fundData.aum,
  expense_ratio: fundData.expense_ratio,
  isValid: isValid,
  error: errorReason,
  data: {
    nav_history: navHistory,
    holdings: holdings,
    risk_metrics: fundData.risk_metrics || {}
  }
};

return [{ json: output }];

const items = $input.all();
const errorReason = items[0]?.json?.error || "Unknown validation error";

return [{
  json: {
    success: false,
    error: errorReason
  }
}];

options.systemMessage:
=You are the central Financial Orchestrator Agent. Your role is to coordinate analysis queries for mutual funds.

### Context Data:
Scheme Name: {{ $json.scheme_name }}
ISIN: {{ $json.isin }}
AMC: {{ $json.amc_name }}
Category: {{ $json.category }}
Enriched: {{ $json.enriched }}
AUM: ₹{{ $json.aum }} Crores
Expense Ratio: {{ $json.expense_ratio }}%
Holdings: {{ JSON.stringify($json.data.holdings) }}
Risk Metrics: Sharpe: {{ $json.data.risk_metrics?.sharpe }}, Beta: {{ $json.data.risk_metrics?.beta }}, StdDev: {{ $json.data.risk_metrics?.std_dev }}

### Routing Logic Rules:
- Inspect the 'Category' field:
  1. If it contains 'Mid Cap', you MUST call the tool 'analyze_midcap_fund'. Pass the complete fund data schema to it.
  2. If it contains 'PSU' or thematic public sector tags, you MUST call the tool 'analyze_psu_fund'. Pass the complete fund data schema to it.
  3. If it contains neither, or if 'Enriched' is false, DO NOT call these tools. Perform standard general mutual fund evaluation internally based on the available metrics (AUM, Expense Ratio, NAV trends, and risk metrics if present).

### Output Report synthesis:
1. If a specialized analyst tool was called, take their markdown report and synthesize it as the core analysis. Start with a header indicating the routing choice (e.g. "Delegated to Midcap Analyst").
2. If evaluated internally, perform standard general fund review (structure, cost efficiency, performance overview) and mark it as "Internal Standard Review".
3. Combine findings into a premium, professional report. Highlight key metrics in bold or list format.

