const items = $input.all();
const fundData = $('Determine Routing & Payload').first().json || {};
const agentData = $('Financial Orchestrator Agent').first().json || {};
const webhookInput = $('Webhook').first().json.body || {};

const sanitize = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;').replace(/'/g, '&#39;');
const truncate = (value, max = 1200) => {
  const text = String(value ?? '').trim();
  if (!text) {
    return '';
  }
  return text.length > max ? `${text.slice(0, max - 1).trimEnd()}…` : text;
};
const compactText = (value) => String(value ?? '').replace(/\s+/g, ' ').trim();
const toNumber = (value) => {
  if (value === null || value === undefined || value === '') {
    return null;
  }
  const cleaned = String(value).replace(/[^0-9.+-]/g, '');
  if (!cleaned) {
    return null;
  }
  const parsed = Number(cleaned);
  return Number.isFinite(parsed) ? parsed : null;
};
const toPercent = (value) => {
  const numeric = toNumber(value);
  if (numeric === null) {
    return 'N/A';
  }
  const adjusted = Math.abs(numeric) <= 1 ? numeric * 100 : numeric;
  return `${adjusted.toFixed(2)}%`;
};
const toDecimal = (value, digits = 2) => {
  const numeric = toNumber(value);
  return numeric === null ? 'N/A' : numeric.toFixed(digits);
};
const labelLookup = (text, labels) => {
  const lines = String(text ?? '').split(/\r?\n/);
  for (const rawLine of lines) {
    const line = rawLine.replace(/^[\s>*-]+/, '').trim();
    const lowered = line.toLowerCase();
    if (labels.some((label) => lowered.includes(label))) {
      const parts = line.split(':');
      return parts.length > 1 ? parts.slice(1).join(':').trim() : line;
    }
  }
  return null;
};

const agentOutput = String(agentData.output ?? agentData.text ?? agentData.response ?? agentData.result ?? '').trim();
const fundName = sanitize(fundData.scheme_name || fundData.name || 'Unknown Fund');
const isin = sanitize(fundData.isin || 'N/A');
const amcName = sanitize(fundData.amc_name || 'N/A');
const category = sanitize(fundData.category || 'General');
const aum = toDecimal(fundData.aum, 2);
const expenseRatio = toPercent(fundData.expense_ratio);
const riskMetrics = fundData.data?.risk_metrics || {};
const holdings = Array.isArray(fundData.data?.holdings) ? fundData.data.holdings : [];
const topHoldings = holdings.slice(0, 5).map((holding, index) => {
  const name = sanitize(holding.security || holding.name || `Holding ${index + 1}`);
  const weight = toPercent(holding.weight);
  return `${index + 1}. ${name} (${weight})`;
});
const topHoldingsMarkdown = topHoldings.length > 0 ? topHoldings.map((line) => `- ${line}`).join('\n') : '- None available from the current data layer.';
const topHoldingsSlack = topHoldings.length > 0 ? topHoldings.map((line) => `• ${line}`).join('\n') : '• None available from the current data layer.';
const navHistory = Array.isArray(fundData.data?.nav_history) ? fundData.data.nav_history : [];
const navWindow = navHistory.length >= 2 ? `${sanitize(navHistory[0]?.date || 'N/A')} → ${sanitize(navHistory[navHistory.length - 1]?.date || 'N/A')}` : 'N/A';
const cagr1y = toPercent(labelLookup(agentOutput, ['1-year cagr', '1y cagr', 'cagr 1y']) || labelLookup(agentOutput, ['1 year cagr']) || riskMetrics.cagr_1y);
const cagr3y = toPercent(labelLookup(agentOutput, ['3-year cagr', '3y cagr', 'cagr 3y']) || labelLookup(agentOutput, ['3 year cagr']) || riskMetrics.cagr_3y);
const cagr5y = toPercent(labelLookup(agentOutput, ['5-year cagr', '5y cagr', 'cagr 5y']) || labelLookup(agentOutput, ['5 year cagr']) || riskMetrics.cagr_5y);
const stdDev = toPercent(riskMetrics.std_dev ?? labelLookup(agentOutput, ['standard deviation', 'std dev', 'volatility']));
const sharpe = toDecimal(riskMetrics.sharpe ?? labelLookup(agentOutput, ['sharpe ratio', 'sharpe']), 2);
const beta = toDecimal(riskMetrics.beta ?? labelLookup(agentOutput, ['beta']), 2);
const maxDrawdown = toPercent(labelLookup(agentOutput, ['max drawdown', 'drawdown']));
const executiveSummary = sanitize(compactText(agentOutput || 'No executive summary was produced.'));
const riskStdDevNumeric = toNumber(riskMetrics.std_dev ?? labelLookup(agentOutput, ['standard deviation', 'std dev', 'volatility']));
const riskFlags = [];
if (riskStdDevNumeric !== null && ((Math.abs(riskStdDevNumeric) <= 1 && Math.abs(riskStdDevNumeric) * 100 >= 22) || Math.abs(riskStdDevNumeric) > 1 && Math.abs(riskStdDevNumeric) >= 22)) {
  riskFlags.push('High volatility');
}
const sharpeNumeric = toNumber(riskMetrics.sharpe ?? labelLookup(agentOutput, ['sharpe ratio', 'sharpe']));
if (sharpeNumeric !== null && sharpeNumeric < 0.5) {
  riskFlags.push('Weak risk-adjusted returns');
}
if (navHistory.length < 20) {
  riskFlags.push('Limited NAV history for deeper analysis');
}
const riskFlagText = riskFlags.length > 0 ? riskFlags.join(', ') : 'No active risk flags';
const hitlStatus = riskFlags.includes('High volatility') ? 'APPROVED' : 'DIRECT_ACTION';
const analystRecommendation = sanitize(truncate(executiveSummary || 'No recommendation was produced.', 1800));
const reportMarkdown = `# Mutual Fund Investment Report: ${fundName}
## Executive Summary
${executiveSummary}

## Fund Profile
- **ISIN**: ${isin} | **AMC**: ${amcName}
- **Category**: ${category} | **Total AUM**: ${aum} Lakhs
- **Expense Ratio**: ${expenseRatio}

## Performance Metrics
- **1-Year CAGR**: ${cagr1y}
- **3-Year CAGR**: ${cagr3y}
- **5-Year CAGR**: ${cagr5y}

## Risk & Volatility Analysis
- **Standard Deviation**: ${stdDev}
- **Sharpe Ratio**: ${sharpe}
- **Beta**: ${beta}
- **Max Drawdown**: ${maxDrawdown}

## Portfolio Holdings Concentration
- **Top 5 Holdings**:
${topHoldingsMarkdown}
- **Major Sector Exposure**: N/A from current payload

## Analyst Recommendation
- **Thesis**: ${analystRecommendation}
- **HITL Status**: ${hitlStatus}`;
const requiredHeaders = ['# Mutual Fund Investment Report:', '## Executive Summary', '## Fund Profile', '## Performance Metrics', '## Risk & Volatility Analysis', '## Portfolio Holdings Concentration', '## Analyst Recommendation'];
const hasRequiredHeaders = requiredHeaders.every((header) => reportMarkdown.includes(header));
const reportComplete = Boolean(reportMarkdown.trim()) && hasRequiredHeaders;
const fallbackMarkdown = `# Mutual Fund Investment Report: Data Unavailable
## Executive Summary
A safe fallback was generated because the phase 8 formatter did not receive a complete report payload.

## Fund Profile
- **ISIN**: ${isin}
- **AMC**: ${amcName}
- **Category**: ${category}

## Performance Metrics
- **1-Year CAGR**: N/A
- **3-Year CAGR**: N/A
- **5-Year CAGR**: N/A

## Risk & Volatility Analysis
- **Standard Deviation**: N/A
- **Sharpe Ratio**: N/A
- **Beta**: N/A
- **Max Drawdown**: N/A

## Portfolio Holdings Concentration
- **Top 5 Holdings**: N/A
- **Major Sector Exposure**: N/A

## Analyst Recommendation
- **Thesis**: Fallback report generated due to missing or malformed source output.
- **HITL Status**: DIRECT_ACTION`;
const finalMarkdown = reportComplete ? reportMarkdown : fallbackMarkdown;
const slackFallbackText = `${fundName} | ISIN ${isin} | 3Y CAGR ${cagr3y} | Sharpe ${sharpe} | Risk ${riskFlagText}`;
const slackBlocks = [
  {
    type: 'header',
    text: {
      type: 'plain_text',
      text: `Mutual Fund Report: ${truncate(fundName, 40)}`,
      emoji: true
    }
  },
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*ISIN:* ${isin}\n*AMC:* ${amcName}\n*Category:* ${category}\n*AUM:* ${aum} Lakhs\n*Expense Ratio:* ${expenseRatio}`
    }
  },
  {
    type: 'section',
    fields: [
      { type: 'mrkdwn', text: `*1Y CAGR*\n${cagr1y}` },
      { type: 'mrkdwn', text: `*3Y CAGR*\n${cagr3y}` },
      { type: 'mrkdwn', text: `*5Y CAGR*\n${cagr5y}` },
      { type: 'mrkdwn', text: `*Sharpe*\n${sharpe}` },
      { type: 'mrkdwn', text: `*Std Dev*\n${stdDev}` },
      { type: 'mrkdwn', text: `*Beta*\n${beta}` }
    ]
  },
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*Executive Summary*\n${truncate(executiveSummary, 1200) || 'No executive summary was produced.'}`
    }
  },
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*Top Holdings*\n${topHoldingsSlack}`
    }
  },
  {
    type: 'context',
    elements: [
      {
        type: 'mrkdwn',
        text: `*Risk Flags:* ${sanitize(riskFlagText)} | *NAV Window:* ${navWindow}`
      }
    ]
  }
];

return [{
  json: {
    ...fundData,
    query: webhookInput.query || '',
    scheme_id: fundData.scheme_code,
    scheme_name: fundData.scheme_name || fundData.name,
    isin,
    amc_name: amcName,
    category,
    enriched: fundData.enriched,
    aum: fundData.aum,
    expense_ratio: fundData.expense_ratio,
    isValid: true,
    error: '',
    data: {
      nav_history: navHistory,
      holdings,
      risk_metrics: riskMetrics
    },
    reportMarkdown: finalMarkdown,
    emailSubject: `Mutual Fund Investment Report: ${fundName}`,
    slackFallbackText,
    slackBlocks: JSON.stringify(slackBlocks),
    deliveryMeta: {
      hasRequiredHeaders,
      reportComplete,
      riskFlags,
      hitlStatus,
      usedFallback: !reportComplete
    }
  }
}];
